@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle italic
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #000000
skinparam classFontColor #000000
skinparam interfaceBackgroundColor #E6E6FA
skinparam interfaceBorderColor #000000
skinparam interfaceFontColor #000000

package "xxx" {
    interface Shape {
        void draw()
    }

    class Circle {
        void draw()
    }

    class Rectangle {
        void draw()
    }

    class Square {
        void draw()
    }

    Circle ..|> Shape : implement
    Rectangle ..|> Shape : implement
    Square ..|> Shape : implement
}

class ShapeFactory {
    Shape getShape()
}

class FactoryPatternDemo {
    void main()
}

FactoryPatternDemo --> ShapeFactory : ask
ShapeFactory --> Shape : create
@enduml
